Get-ScheduledTask | ForEach-Object {
    $info = $_ | Get-ScheduledTaskInfo -ErrorAction SilentlyContinue
    $principal = $_.Principal
    $actions = $_.Actions | ForEach-Object { $_.Execute + ' ' + $_.Arguments }
    [PSCustomObject]@{
        Name      = $_.TaskName
        Path      = $_.TaskPath
        RunAs     = $principal.UserId
        RunLevel  = $principal.RunLevel
        Actions   = $actions -join '; '
        LastRun   = $info.LastRunTime
        LastResult= $info.LastTaskResult
    }
} | Where-Object { $_.RunAs -match 'SYSTEM|Administrator' } | Format-Table -AutoSize

Get-ScheduledTask | ForEach-Object {
    $task = $_
    $_.Actions | Where-Object { $_.Execute -match 'powershell|cmd|wscript|cscript' } | ForEach-Object {
        $scriptPath = $_.Arguments -replace '.*-[Ff]ile\s+',''
        $scriptPath = $scriptPath.Trim('"').Split(' ')[0]
        if ($scriptPath -and (Test-Path $scriptPath)) {
            $acl = Get-Acl $scriptPath -ErrorAction SilentlyContinue
            $acl.Access | Where-Object {
                $_.FileSystemRights -match 'Write|FullControl' -and
                $_.IdentityReference -notmatch 'SYSTEM|TrustedInstaller|Administrators'
            } | ForEach-Object {
                Write-Output "TASK: $($task.TaskName) | SCRIPT: $scriptPath | ACE: $($_.IdentityReference)"
            }
        }
    }
}

Get-ScheduledTask | Where-Object {
    $_.Principal.UserId -match 'SYSTEM|S-1-5-18' -or
    $_.Principal.RunLevel -eq 'Highest'
} | ForEach-Object {
    $actions = $_.Actions | ForEach-Object { $_.Execute + ' ' + $_.Arguments }
    Write-Output "Task: $($_.TaskName) | RunAs: $($_.Principal.UserId) | RunLevel: $($_.Principal.RunLevel)"
    Write-Output "  Actions: $($actions -join '; ')"
}

Get-ScheduledTask | ForEach-Object {
    $_.Actions | Where-Object { $_.Execute -match '%[A-Z]+%' -or $_.Arguments -match '%[A-Z]+%' } | ForEach-Object {
        Write-Output "Task: $($task.TaskName) | Action: $($_.Execute) $($_.Arguments)"
    }
}

$taskFolder = 'C:\Windows\System32\Tasks'
Get-ChildItem $taskFolder -Recurse -File | ForEach-Object {
    $xml = [xml](Get-Content $_.FullName -ErrorAction SilentlyContinue)
    $comHandlers = $xml.SelectNodes('//ComHandler')
    if ($comHandlers.Count -gt 0) {
        Write-Output "Task: $($_.Name)"
        $comHandlers | ForEach-Object { Write-Output "  CLSID: $($_.ClassId)" }
    }
}

for /f "tokens=1 delims=," %t in ('schtasks /query /fo CSV /nh') do (
    schtasks /query /tn "%t" /xml ONE 2>nul >> C:\Temp\tasks_export.xml
)
findstr /I "password pass user author" C:\Temp\tasks_export.xml

Get-ChildItem 'C:\Windows\System32\Tasks' -Recurse -File | ForEach-Object {
    $content = Get-Content $_.FullName -ErrorAction SilentlyContinue -Raw
    if ($content -match 'password|passwd|credential|RunAs.*\\') {
        Write-Output "=== $($_.FullName) ==="
        $content | Select-String -Pattern 'password|passwd|credential' -CaseSensitive:$false
    }
}
